class CreateInvoiceAction {
    public function __construct(
        private InvoiceRepository $invoices,
        private TaxCalculator $taxCalculator
    ) {}

    public function __invoke(CreateInvoiceDTO $dto): Invoice {
        $tax = $this->taxCalculator->calculate($dto->amount, $dto->country);
        $invoice = Invoice::create([
            'amount' => $dto->amount,
            'tax' => $tax,
            'total' => $dto->amount + $tax,
            'user_id' => $dto->userId,
        ]);
        return $invoice;
    }
}

interface Specification {
    public function isSatisfiedBy(mixed $candidate): bool;
    public function toQuery(Builder $query): Builder;
}

class ActiveUserSpec implements Specification {
    public function isSatisfiedBy(mixed $candidate): bool {
        return $candidate->is_active && $candidate->email_verified_at !== null;
    }
    public function toQuery(Builder $query): Builder {
        return $query->where('is_active', true)->whereNotNull('email_verified_at');
    }
}

