interface FileStorageInterface {
    public function store(string $path, string $contents): string;
    public function get(string $path): ?string;
    public function delete(string $path): bool;
}

class S3Adapter implements FileStorageInterface {
    public function __construct(private S3Client $client, private string $bucket) {}
    public function store(string $path, string $contents): string {
        $this->client->putObject(['Bucket' => $this->bucket, 'Key' => $path, 'Body' => $contents]);
        return $path;
    }
    public function get(string $path): ?string {
        try {
            $result = $this->client->getObject(['Bucket' => $this->bucket, 'Key' => $path]);
            return $result['Body']->getContents();
        } catch (S3Exception $e) { return null; }
    }
    public function delete(string $path): bool {
        $this->client->deleteObject(['Bucket' => $this->bucket, 'Key' => $path]);
        return true;
    }
}

