class Order extends AggregateRoot {
    private Collection $items;
    private OrderStatus $status;

    public function addItem(Product $product, int $quantity): void {
        if ($this->status !== OrderStatus::Draft) {
            throw new DomainException('Cannot modify a non-draft order');
        }
        $this->items->push(new OrderItem($product, $quantity));
        $this->recordEvent(new ItemAddedToOrder($this->id, $product->id, $quantity));
    }

    public function place(): void {
        if ($this->items->isEmpty()) {
            throw new DomainException('Cannot place an empty order');
        }
        $this->status = OrderStatus::Placed;
        $this->recordEvent(new OrderPlaced($this->id));
    }
}

// With spatie/laravel-permission
class RoleMiddleware {
    public function handle(Request $request, Closure $next, string $role): Response {
        if (!$request->user()->hasRole($role)) {
            abort(403, 'Insufficient permissions');
        }
        return $next($request);
    }
}

