class ProcessImageUpload implements ShouldQueue {
    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;

    public function __construct(private Image $image) {}

    public function handle(ImageProcessor $processor): void {
        $processor->resize($this->image, 800, 600);
        $processor->generateThumbnail($this->image, 200, 200);
        $this->image->update(['processed' => true]);
    }

    public function failed(Throwable $e): void {
        Log::error('Image processing failed', ['image_id' => $this->image->id, 'error' => $e->getMessage()]);
    }
}
