interface MenuComponent {
    public function render(): string;
}

class MenuItem implements MenuComponent {
    public function __construct(private string $label, private string $url) {}
    public function render(): string {
        return \<a href='{$this->url}'>{$this->label}</a>";
    }
}

class SubMenu implements MenuComponent {
    private array $children = [];
    public function __construct(private string $label) {}
    public function add(MenuComponent $item): void { $this->children[] = $item; }
    public function render(): string {
        $html = "<li>{$this->label}<ul>";
        foreach ($this->children as $child) { $html .= '<li>' . $child->render() . '</li>'; }
        return $html . '</ul></li>';
    }
}"
